247→// schedulingAlgorithm runs fitering and scoring phases for a single pod,
248→// together with post filter when the pod is unschedulable.
249→func (sched *Scheduler) schedulingAlgorithm(
250→	ctx context.Context,
251→	state fwk.CycleState,
252→	schedFramework framework.Framework,
253→	podInfo *framework.QueuedPodInfo,
254→	start time.Time,
255→) (ScheduleResult, *fwk.Status) {
256→	defer func() {
257→		metrics.SchedulingAlgorithmLatency.Observe(metrics.SinceInSeconds(start))
258→	}()
259→
260→	pod := podInfo.Pod
261→
262→	logger := klog.FromContext(ctx)
263→	scheduleResult, err := sched.SchedulePod(ctx, schedFramework, state, podInfo)
264→	if err != nil {
265→		if err == ErrNoNodesAvailable {
266→			status := fwk.NewStatus(fwk.UnschedulableAndUnresolvable).WithError(err)
267→			return ScheduleResult{nominatingInfo: clearNominatedNode}, status
268→		}
269→
270→		fitError, ok := err.(*framework.FitError)
271→		if !ok {
272→			logger.Error(err, "Error selecting node for pod", "pod", klog.KObj(pod))
273→			return ScheduleResult{nominatingInfo: clearNominatedNode}, fwk.AsStatus(err)
274→		}
275→
276→		// SchedulePod() may have failed because the pod would not fit on any host, so we try to
277→		// preempt, with the expectation that the next time the pod is tried for scheduling it
278→		// will fit due to the preemption. It is also possible that a different pod will schedule
279→		// into the resources that were preempted, but this is harmless.
280→
281→		if !schedFramework.HasPostFilterPlugins() {
282→			logger.V(3).Info("No PostFilter plugins are registered, so no preemption will be performed")
283→			return ScheduleResult{nominatingInfo: clearNominatedNode}, fwk.NewStatus(fwk.Unschedulable).WithError(err)
284→		}
285→
286→		// Run PostFilter plugins to attempt to make the pod schedulable in a future scheduling cycle.
287→		result, status := schedFramework.RunPostFilterPlugins(ctx, state, pod, fitError.Diagnosis.NodeToStatus)
288→		msg := status.Message()
289→		fitError.Diagnosis.PostFilterMsg = msg
290→		if status.Code() == fwk.Error {
291→			utilruntime.HandleErrorWithContext(ctx, nil, "Status after running PostFilter plugins for pod", "pod", klog.KObj(pod), "status", msg)
292→		} else {
293→			logger.V(5).Info("Status after running PostFilter plugins for pod", "pod", klog.KObj(pod), "status", msg)
294→		}
295→
296→		var nominatingInfo *fwk.NominatingInfo
297→		if result != nil {
298→			nominatingInfo = result.NominatingInfo
299→		}
300→		return ScheduleResult{nominatingInfo: nominatingInfo}, fwk.NewStatus(fwk.Unschedulable).WithError(err)
301→	}
302→	return scheduleResult, nil
303→}
