305→// assumeAndReserve assumes and reserves the pod in scheduler's memory.
306→func (sched *Scheduler) assumeAndReserve(
307→	ctx context.Context,
308→	state fwk.CycleState,
309→	schedFramework framework.Framework,
310→	podInfo *framework.QueuedPodInfo,
311→	scheduleResult ScheduleResult,
312→) (*framework.QueuedPodInfo, *fwk.Status) {
313→	logger := klog.FromContext(ctx)
314→	// Tell the cache to assume that a pod now is running on a given node, even though it hasn't been bound yet.
315→	// This allows us to keep scheduling without waiting on binding to occur.
316→	assumedPodInfo := podInfo.DeepCopy()
317→	assumedPod := assumedPodInfo.Pod
318→	// assume modifies `assumedPod` by setting NodeName=scheduleResult.SuggestedHost
319→	err := sched.assume(logger, assumedPodInfo, scheduleResult.SuggestedHost)
320→	if err != nil {
321→		// This is most probably result of a BUG in retrying logic.
322→		// We report an error here so that pod scheduling can be retried.
323→		// This relies on the fact that Error will check if the pod has been bound
324→		// to a node and if so will not add it back to the unscheduled pods queue
325→		// (otherwise this would cause an infinite loop).
326→		return assumedPodInfo, fwk.AsStatus(err)
327→	}
328→
329→	// Run the Reserve method of reserve plugins.
330→	if sts := schedFramework.RunReservePluginsReserve(ctx, state, assumedPod, scheduleResult.SuggestedHost); !sts.IsSuccess() {
331→		// trigger un-reserve to clean up state associated with the reserved Pod
332→		err := sched.unreserveAndForget(ctx, state, schedFramework, assumedPodInfo, scheduleResult.SuggestedHost)
333→		if err != nil {
334→			utilruntime.HandleErrorWithContext(ctx, err, "ForgetPod failed")
335→		}
336→
337→		if sts.IsRejected() {
338→			fitErr := &framework.FitError{
339→				NumAllNodes: 1,
340→				Pod:         podInfo.Pod,
341→				Diagnosis: framework.Diagnosis{
342→					NodeToStatus: framework.NewDefaultNodeToStatus(),
343→				},
344→			}
345→			fitErr.Diagnosis.NodeToStatus.Set(scheduleResult.SuggestedHost, sts)
346→			fitErr.Diagnosis.AddPluginStatus(sts)
347→			return assumedPodInfo, fwk.NewStatus(sts.Code()).WithError(fitErr)
348→		}
349→		return assumedPodInfo, sts
350→	}
351→	return assumedPodInfo, nil
352→}
