354→// unreserveAndForget unreserves and forgets the pod from scheduler's memory.
355→// This function shouldn't be called during binding cycle with a pod that has the NeedsPodGroupScheduling set to true,
356→// but this shouldn't happen, because such pods cannot reach binding.
357→func (sched *Scheduler) unreserveAndForget(
358→	ctx context.Context,
359→	state fwk.CycleState,
360→	schedFramework framework.Framework,
361→	assumedPodInfo *framework.QueuedPodInfo,
362→	nodeName string,
363→) error {
364→	logger := klog.FromContext(ctx)
365→
366→	schedFramework.RunReservePluginsUnreserve(ctx, state, assumedPodInfo.Pod, nodeName)
367→	if assumedPodInfo.NeedsPodGroupScheduling {
368→		err := sched.nodeInfoSnapshot.ForgetPod(logger, assumedPodInfo.Pod)
369→		if err != nil {
370→			return err
371→		}
372→		if assumedPodInfo.Pod.Status.NominatedNodeName != "" {
373→			// Assume method removed the nomination, but since we are reverting that stage for pod groups,
374→			// we need to revert that operation as well.
375→			if sched.SchedulingQueue != nil {
376→				nominatingInfo := &fwk.NominatingInfo{
377→					NominatedNodeName: assumedPodInfo.Pod.Status.NominatedNodeName,
378→					NominatingMode:    fwk.ModeOverride,
379→				}
380→				// AssumedPodInfo can be used here, because the whole pod object is not stored in the nominator.
381→				sched.SchedulingQueue.AddNominatedPod(logger, assumedPodInfo.PodInfo, nominatingInfo)
382→			}
383→		}
384→		return nil
385→	}
386→	return sched.Cache.ForgetPod(logger, assumedPodInfo.Pod)
387→}
