389→// bindingCycle tries to bind an assumed Pod.
390→func (sched *Scheduler) bindingCycle(
391→	ctx context.Context,
392→	state fwk.CycleState,
393→	schedFramework framework.Framework,
394→	scheduleResult ScheduleResult,
395→	assumedPodInfo *framework.QueuedPodInfo,
396→	start time.Time,
397→	podsToActivate *framework.PodsToActivate) *fwk.Status {
398→	logger := klog.FromContext(ctx)
399→
400→	assumedPod := assumedPodInfo.Pod
401→
402→	var preFlightStatus *fwk.Status
403→	if sched.nominatedNodeNameForExpectationEnabled {
404→		preFlightStatus = schedFramework.RunPreBindPreFlights(ctx, state, assumedPod, scheduleResult.SuggestedHost)
405→		if preFlightStatus.Code() == fwk.Error ||
406→			// Unschedulable status is not supported in PreBindPreFlight and hence we regard it as an error.
407→			preFlightStatus.IsRejected() {
408→			return preFlightStatus
409→		}
410→		if preFlightStatus.IsSuccess() || schedFramework.WillWaitOnPermit(ctx, assumedPod) {
411→			// Add NominatedNodeName to tell the external components (e.g., the cluster autoscaler) that the pod is about to be bound to the node.
412→			// We only do this when any of WaitOnPermit or PreBind will work because otherwise the pod will be soon bound anyway.
413→			if err := updatePod(ctx, sched.client, schedFramework.APICacher(), assumedPod, nil, &fwk.NominatingInfo{
414→				NominatedNodeName: scheduleResult.SuggestedHost,
415→				NominatingMode:    fwk.ModeOverride,
416→			}); err != nil {
417→				logger.Error(err, "Failed to update the nominated node name in the binding cycle", "pod", klog.KObj(assumedPod), "nominatedNodeName", scheduleResult.SuggestedHost)
418→				// We continue the processing because it's not critical enough to stop binding cycles here.
419→			}
420→		}
421→	}
422→
423→	// Run "permit" plugins.
424→	if status := schedFramework.WaitOnPermit(ctx, assumedPod); !status.IsSuccess() {
425→		if status.IsRejected() {
426→			fitErr := &framework.FitError{
427→				NumAllNodes: 1,
428→				Pod:         assumedPodInfo.Pod,
429→				Diagnosis: framework.Diagnosis{
430→					NodeToStatus:         framework.NewDefaultNodeToStatus(),
431→					UnschedulablePlugins: sets.New(status.Plugin()),
432→				},
433→			}
434→			fitErr.Diagnosis.NodeToStatus.Set(scheduleResult.SuggestedHost, status)
435→			return fwk.NewStatus(status.Code()).WithError(fitErr)
436→		}
437→		return status
438→	}
439→
440→	// Any failures after this point cannot lead to the Pod being considered unschedulable.
441→	// We define the Pod as "unschedulable" only when Pods are rejected at specific extension points, and Permit is the last one in the scheduling/binding cycle.
442→	// If a Pod fails on PreBind or Bind, it should be moved to BackoffQ for retry.
443→	//
444→	// We can call Done() here because
445→	// we can free the cluster events stored in the scheduling queue sooner, which is worth for busy clusters memory consumption wise.
446→	sched.SchedulingQueue.Done(assumedPod.UID)
447→
448→	// If we are going to run prebind plugins we put the pod in binding map to optimize preemption.
