469→	if status := sched.bind(ctx, schedFramework, assumedPod, scheduleResult.SuggestedHost, state); !status.IsSuccess() {
470→		return status
471→	}
472→
473→	// Calculating nodeResourceString can be heavy. Avoid it if klog verbosity is below 2.
474→	logger.V(2).Info("Successfully bound pod to node", "pod", klog.KObj(assumedPod), "node", scheduleResult.SuggestedHost, "evaluatedNodes", scheduleResult.EvaluatedNodes, "feasibleNodes", scheduleResult.FeasibleNodes)
475→	metrics.PodScheduled(schedFramework.ProfileName(), metrics.SinceInSeconds(start))
476→	metrics.PodSchedulingAttempts.Observe(float64(assumedPodInfo.Attempts))
477→	if assumedPodInfo.InitialAttemptTimestamp != nil {
478→		metrics.PodSchedulingSLIDuration.WithLabelValues(getAttemptsLabel(assumedPodInfo)).Observe(metrics.SinceInSeconds(*assumedPodInfo.InitialAttemptTimestamp))
479→	}
480→	// Count pods scheduled after being flushed from unschedulablePods
481→	if assumedPodInfo.WasFlushedFromUnschedulable {
482→		logger.V(4).Info("Pod scheduled after flush from unschedulablePods", "pod", klog.KObj(assumedPodInfo.Pod), "unschedulablePlugins", assumedPodInfo.UnschedulablePlugins, "pendingPlugins", assumedPodInfo.PendingPlugins)
483→		metrics.PodScheduledAfterFlush.Inc()
484→	}
485→	// Run "postbind" plugins.
486→	schedFramework.RunPostBindPlugins(ctx, state, assumedPod, scheduleResult.SuggestedHost)
487→
488→	// At the end of a successful binding cycle, move up Pods if needed.
489→	if len(podsToActivate.Map) != 0 {
490→		sched.SchedulingQueue.Activate(logger, podsToActivate.Map)
491→		// Unlike the logic in schedulingCycle(), we don't bother deleting the entries
492→		// as `podsToActivate.Map` is no longer consumed.
493→	}
494→
495→	return nil
496→}
497→
498→func (sched *Scheduler) handleBindingCycleError(
499→	ctx context.Context,
500→	state fwk.CycleState,
501→	fwk framework.Framework,
502→	podInfo *framework.QueuedPodInfo,
503→	start time.Time,
504→	scheduleResult ScheduleResult,
505→	status *fwk.Status) {
506→	logger := klog.FromContext(ctx)
507→
508→	assumedPod := podInfo.Pod
509→	// trigger un-reserve plugins to clean up state associated with the reserved Pod
510→	if forgetErr := sched.unreserveAndForget(ctx, state, fwk, podInfo, scheduleResult.SuggestedHost); forgetErr != nil {
511→		utilruntime.HandleErrorWithContext(ctx, forgetErr, "ForgetPod failed")
512→	} else {
513→		// "Forget"ing an assumed Pod in binding cycle should be treated as a PodDelete event,
514→		// as the assumed Pod had occupied a certain amount of resources in scheduler cache.
515→		//
516→		// Avoid moving the assumed Pod itself as it's always Unschedulable.
517→		// It's intentional to "defer" this operation; otherwise MoveAllToActiveOrBackoffQueue() would
518→		// add this event to in-flight events and thus move the assumed pod to backoffQ anyways if the plugins don't have appropriate QueueingHint.
519→		if status.IsRejected() {
520→			defer sched.SchedulingQueue.MoveAllToActiveOrBackoffQueue(logger, framework.EventAssignedPodDelete, assumedPod, nil, func(pod *v1.Pod) bool {
521→				return assumedPod.UID != pod.UID
522→			})
523→		} else {
524→			sched.SchedulingQueue.MoveAllToActiveOrBackoffQueue(logger, framework.EventAssignedPodDelete, assumedPod, nil, nil)
525→		}
526→	}
527→
528→	sched.FailureHandler(ctx, fwk, podInfo, status, clearNominatedNode, start)
529→}
530→
531→func (sched *Scheduler) frameworkForPod(pod *v1.Pod) (framework.Framework, error) {
532→	fwk, ok := sched.Profiles[pod.Spec.SchedulerName]
533→	if !ok {
534→		return nil, fmt.Errorf("profile not found for scheduler name %q", pod.Spec.SchedulerName)
535→	}
536→	return fwk, nil
537→}
538→
539→// skipPodSchedule returns true if we could skip scheduling the pod for specified cases.
540→func (sched *Scheduler) skipPodSchedule(ctx context.Context, fwk framework.Framework, pod *v1.Pod) bool {
541→	// Case 1: pod is being deleted.
542→	if pod.DeletionTimestamp != nil {
543→		fwk.EventRecorder().Eventf(pod, nil, v1.EventTypeWarning, "FailedScheduling", "Scheduling", "skip schedule deleting pod: %v/%v", pod.Namespace, pod.Name)
544→		klog.FromContext(ctx).V(3).Info("Skip schedule deleting pod", "pod", klog.KObj(pod))
545→		return true
546→	}
547→
548→	// Case 2: pod that has been assumed could be skipped.
549→	// An assumed pod can be added again to the scheduling queue if it got an update event
550→	// during its previous scheduling cycle but before getting assumed.
551→	isAssumed, err := sched.Cache.IsAssumedPod(pod)
552→	if err != nil {
553→		utilruntime.HandleErrorWithContext(ctx, err, "Failed to check whether pod is assumed", "pod", klog.KObj(pod))
554→		return false
555→	}
556→	return isAssumed
557→}
558→
559→// schedulePod tries to schedule the given pod to one of the nodes in the node list.
560→// If it succeeds, it will return the name of the node.
561→// If it fails, it will return a FitError with reasons.
562→func (sched *Scheduler) schedulePod(ctx context.Context, fwk framework.Framework, state fwk.CycleState, podInfo *framework.QueuedPodInfo) (result ScheduleResult, err error) {
563→	pod := podInfo.Pod
564→	trace := utiltrace.New("Scheduling", utiltrace.Field{Key: "namespace", Value: pod.Namespace}, utiltrace.Field{Key: "name", Value: pod.Name})
565→	defer trace.LogIfLong(100 * time.Millisecond)
566→	if !podInfo.NeedsPodGroupScheduling {
567→		if err := sched.Cache.UpdateSnapshot(klog.FromContext(ctx), sched.nodeInfoSnapshot); err != nil {
568→			return result, err
569→		}
570→		trace.Step("Snapshotting scheduler cache and node infos done")
571→	}
572→
573→	if sched.nodeInfoSnapshot.NumNodes() == 0 {
574→		return result, ErrNoNodesAvailable
575→	}
576→
577→	feasibleNodes, diagnosis, nodeHint, signature, err := sched.findNodesThatFitPod(ctx, fwk, state, podInfo.Pod)
578→	if err != nil {
579→		return result, err
580→	}
581→	trace.Step("Computing predicates done")
582→
583→	if len(feasibleNodes) == 0 {
584→		return result, &framework.FitError{
585→			Pod:         pod,
586→			NumAllNodes: sched.nodeInfoSnapshot.NumNodes(),
587→			Diagnosis:   diagnosis,
588→		}
589→	}
590→
591→	// When only one node after predicate, just use it.
592→	if len(feasibleNodes) == 1 {
593→		node := feasibleNodes[0].Node().Name
594→		if utilfeature.DefaultFeatureGate.Enabled(features.OpportunisticBatching) {
595→			fwk.StoreScheduleResults(ctx, signature, nodeHint, node, nil, sched.CurrentCycle())
596→		}
597→		return ScheduleResult{
598→			SuggestedHost:  node,
599→			EvaluatedNodes: 1 + diagnosis.NodeToStatus.Len(),
600→			FeasibleNodes:  1,
601→		}, nil
602→	}
603→
604→	priorityList, err := prioritizeNodes(ctx, sched.Extenders, fwk, state, pod, feasibleNodes)
605→	if err != nil {
606→		return result, err
607→	}
608→
609→	sortedPrioritizedNodes := newSortedNodeScores(priorityList)
610→	node := sortedPrioritizedNodes.Pop()
611→	trace.Step("Prioritizing done")
612→
613→	if utilfeature.DefaultFeatureGate.Enabled(features.OpportunisticBatching) {
614→		fwk.StoreScheduleResults(ctx, signature, nodeHint, node, sortedPrioritizedNodes, sched.CurrentCycle())
615→	}
616→
617→	return ScheduleResult{
618→		SuggestedHost:  node,
619→		EvaluatedNodes: len(feasibleNodes) + diagnosis.NodeToStatus.Len(),
620→		FeasibleNodes:  len(feasibleNodes),
621→	}, err
622→}
623→
624→// Filters the nodes to find the ones that fit the pod based on the framework
625→// filter plugins and filter extenders.
626→func (sched *Scheduler) findNodesThatFitPod(ctx context.Context, schedFramework framework.Framework, state fwk.CycleState, pod *v1.Pod) ([]fwk.NodeInfo, framework.Diagnosis, string, fwk.PodSignature, error) {
627→	logger := klog.FromContext(ctx)
628→	diagnosis := framework.Diagnosis{
629→		NodeToStatus: framework.NewDefaultNodeToStatus(),
630→	}
631→	allNodes, err := sched.nodeInfoSnapshot.NodeInfos().List()
632→	if err != nil {
633→		return nil, diagnosis, "", nil, err
634→	}
635→	// Run "prefilter" plugins.
636→	preRes, s, unscheduledPlugins := schedFramework.RunPreFilterPlugins(ctx, state, pod)
637→	diagnosis.UnschedulablePlugins = unscheduledPlugins
638→	if !s.IsSuccess() {
639→		if !s.IsRejected() {
640→			return nil, diagnosis, "", nil, s.AsError()
641→		}
642→		// All nodes in NodeToStatus will have the same status so that they can be handled in the preemption.
643→		diagnosis.NodeToStatus.SetAbsentNodesStatus(s)
644→
645→		// Record the messages from PreFilter in Diagnosis.PreFilterMsg.
646→		msg := s.Message()
647→		diagnosis.PreFilterMsg = msg
648→		logger.V(5).Info("Status after running PreFilter plugins for pod", "pod", klog.KObj(pod), "status", msg)
649→		diagnosis.AddPluginStatus(s)
650→		return nil, diagnosis, "", nil, nil
651→	}
652→
653→	var nodeHint string
654→	var signature fwk.PodSignature
655→	if utilfeature.DefaultFeatureGate.Enabled(features.OpportunisticBatching) {
656→		// We get the node hint even if we have a nominated name for simplicity, but we could potentially avoid it
657→		// in this scenario in the future.
658→		nodeHint, signature = schedFramework.GetNodeHint(ctx, pod, state, sched.CurrentCycle())
659→	}
660→
661→	// "NominatedNodeName" can potentially be set in a previous scheduling cycle as a result of preemption.
662→	// This node is likely the only candidate that will fit the pod, and hence we try it first before iterating over all nodes.
663→	// We take the same tack for hinted nodes from the batch module.
664→	if len(pod.Status.NominatedNodeName) > 0 || len(nodeHint) > 0 {
665→		feasibleNodes, err := sched.evaluateNominatedNode(ctx, pod, schedFramework, state, nodeHint, diagnosis)
666→		if err != nil {
667→			utilruntime.HandleErrorWithContext(ctx, err, "Evaluation failed on nominated node", "pod", klog.KObj(pod), "node", pod.Status.NominatedNodeName)
668→		}
669→		// Nominated node passes all the filters, scheduler is good to assign this node to the pod.
670→		if len(feasibleNodes) != 0 {
671→			return feasibleNodes, diagnosis, nodeHint, signature, nil
672→		}
673→	}
674→
675→	nodes := allNodes
676→	if !preRes.AllNodes() {
677→		nodes = make([]fwk.NodeInfo, 0, len(preRes.NodeNames))
678→		for nodeName := range preRes.NodeNames {
679→			// PreRes may return nodeName(s) which do not exist; we verify
680→			// node exists in the Snapshot.
681→			if nodeInfo, err := sched.nodeInfoSnapshot.Get(nodeName); err == nil {
682→				nodes = append(nodes, nodeInfo)
683→			}
684→		}
685→		diagnosis.NodeToStatus.SetAbsentNodesStatus(fwk.NewStatus(fwk.UnschedulableAndUnresolvable, fmt.Sprintf("node(s) didn't satisfy plugin(s) %v", sets.List(unscheduledPlugins))))
686→	}
687→	feasibleNodes, err := sched.findNodesThatPassFilters(ctx, schedFramework, state, pod, &diagnosis, nodes)
688→	// always try to update the sched.nextStartNodeIndex regardless of whether an error has occurred
689→	// this is helpful to make sure that all the nodes have a chance to be searched
690→	processedNodes := len(feasibleNodes) + diagnosis.NodeToStatus.Len()
691→	sched.nextStartNodeIndex = (sched.nextStartNodeIndex + processedNodes) % len(allNodes)
692→	if err != nil {
693→		return nil, diagnosis, nodeHint, signature, err
694→	}
695→
696→	feasibleNodesAfterExtender, err := findNodesThatPassExtenders(ctx, sched.Extenders, pod, feasibleNodes, diagnosis.NodeToStatus)
697→	if err != nil {
698→		return nil, diagnosis, nodeHint, signature, err
699→	}

